/**
 * Tests for gh-rate-limit-tracker PostToolUse hook.
 *
 * Verifies: detection of primary/secondary/HTTP-403 rate limits, pass-through
 * for non-gh commands, silent success when tool_response is clean, and that
 * additionalContext carries actionable guidance.
 */

import { describe, test, expect } from 'vitest';
import {
  ghRateLimitTracker,
  detectRateLimit,
  isGhCommand,
  buildContext,
} from '../../../posttool/bash/gh-rate-limit-tracker.js';
import type { HookInput } from '../../../types.js';

function makeInput(command: string, stdout = '', stderr = ''): HookInput {
  return {
    hook_event_name: 'PostToolUse',
    session_id: 'test-session',
    transcript_path: '/tmp/transcript.jsonl',
    cwd: '/tmp',
    tool_name: 'Bash',
    tool_input: { command },
    tool_response: { stdout, stderr },
  } as unknown as HookInput;
}

describe('gh-rate-limit-tracker', () => {
  describe('isGhCommand', () => {
    test('matches bare gh invocation', () => {
      expect(isGhCommand('gh pr list')).toBe(true);
    });

    test('matches absolute path to gh', () => {
      expect(isGhCommand('/usr/bin/gh pr view 123')).toBe(true);
    });

    test('matches gh with env var prefix', () => {
      expect(isGhCommand('GH_TOKEN=xyz gh api rate_limit')).toBe(true);
    });

    test('rejects non-gh commands', () => {
      expect(isGhCommand('git fetch origin')).toBe(false);
      expect(isGhCommand('echo "gh in a string"')).toBe(false);
      expect(isGhCommand('ghostty --version')).toBe(false);
    });
  });

  describe('detectRateLimit', () => {
    test('detects primary rate limit', () => {
      const out = 'gh: API rate limit exceeded for user xyz. Please wait.';
      expect(detectRateLimit(out)?.reason).toBe('primary');
    });

    test('extracts reset timestamp from primary message', () => {
      const out =
        'API rate limit exceeded. Will be reset at 2026-04-21 09:45:00 UTC';
      const hit = detectRateLimit(out);
      expect(hit?.reason).toBe('primary');
      expect(hit?.resetAt).toContain('2026-04-21');
    });

    test('detects secondary rate limit', () => {
      const out = 'You have exceeded a secondary rate limit. Try again later.';
      expect(detectRateLimit(out)?.reason).toBe('secondary');
    });

    test('detects HTTP 403 combined with rate-limit phrase', () => {
      const out = 'HTTP/2 403\nx-ratelimit-remaining: 0\nrate limit exceeded';
      expect(detectRateLimit(out)?.reason).toBe('http-403');
    });

    test('does NOT trigger on plain 403 without rate-limit phrasing', () => {
      // Permission-denied 403 should pass through cleanly
      expect(detectRateLimit('HTTP/2 403\nResource not accessible by integration')).toBeNull();
    });

    test('returns null on clean output', () => {
      expect(detectRateLimit('{"number": 1434, "title": "PR"}')).toBeNull();
      expect(detectRateLimit('')).toBeNull();
    });
  });

  describe('buildContext', () => {
    test('primary limit with reset timestamp includes the timestamp', () => {
      const ctx = buildContext('primary', '2026-04-21 09:45:00 UTC');
      expect(ctx).toContain('2026-04-21 09:45:00 UTC');
      expect(ctx).toMatch(/Do not retry/i);
    });

    test('primary limit without reset falls back to gh api rate_limit hint', () => {
      const ctx = buildContext('primary');
      expect(ctx).toContain('gh api rate_limit');
    });

    test('secondary limit mentions 60-second typical clearance', () => {
      const ctx = buildContext('secondary');
      expect(ctx).toMatch(/secondary rate limit/i);
      expect(ctx).toMatch(/60 seconds/i);
    });

    test('always references the skill-level guidance for discoverability', () => {
      expect(buildContext('primary').toLowerCase()).toContain('github-operations');
    });
  });

  describe('handler integration', () => {
    test('non-gh command returns silent success', async () => {
      const result = await ghRateLimitTracker(makeInput('git status', 'clean'));
      // outputSilentSuccess returns { continue: true } per CC 2.1.7 contract
      expect(result).toMatchObject({ continue: true });
    });

    test('gh command with clean output returns silent success', async () => {
      const result = await ghRateLimitTracker(
        makeInput('gh pr list', '[{"number": 1434}]'),
      );
      expect(result).toMatchObject({ continue: true });
      // No additionalContext on clean path
      expect(
        (result as { hookSpecificOutput?: { additionalContext?: string } })
          .hookSpecificOutput?.additionalContext,
      ).toBeUndefined();
    });

    test('gh command with primary rate-limit injects additionalContext', async () => {
      const result = await ghRateLimitTracker(
        makeInput(
          'gh pr checks 1434',
          '',
          'API rate limit exceeded for user xyz. Will be reset at 2026-04-21 10:00:00 UTC.',
        ),
      );
      const ctx =
        (result as { hookSpecificOutput?: { additionalContext?: string } })
          .hookSpecificOutput?.additionalContext || '';
      expect(ctx).toMatch(/Do not retry/i);
      expect(ctx).toContain('2026-04-21 10:00:00 UTC');
    });

    test('gh command with secondary rate-limit injects additionalContext', async () => {
      const result = await ghRateLimitTracker(
        makeInput(
          'gh api repos/org/repo/issues',
          '',
          'You have exceeded a secondary rate limit and have been blocked temporarily.',
        ),
      );
      const ctx =
        (result as { hookSpecificOutput?: { additionalContext?: string } })
          .hookSpecificOutput?.additionalContext || '';
      expect(ctx).toMatch(/secondary/i);
      expect(ctx).toMatch(/stop the loop/i);
    });

    test('clean 403 permission error does NOT trigger (false-positive guard)', async () => {
      const result = await ghRateLimitTracker(
        makeInput(
          'gh pr view 1434',
          '',
          'HTTP/2 403\nmessage: Resource not accessible by integration',
        ),
      );
      expect(
        (result as { hookSpecificOutput?: { additionalContext?: string } })
          .hookSpecificOutput?.additionalContext,
      ).toBeUndefined();
    });
  });
});
